<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background: #f4f6f9; color: #333; padding: 20px; max-width: 800px; margin: 0 auto; }
  h1 { text-align: center; margin-bottom: 24px; font-size: 1.6rem; color: #222; }
  h2 { font-size: 1.1rem; margin-bottom: 10px; color: #444; }

  /* Form */
  .form-section { background: #fff; border-radius: 8px; padding: 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.08); }
  .form-row { display: flex; flex-wrap: wrap; gap: 10px; align-items: flex-end; margin-bottom: 10px; }
  .form-group { display: flex; flex-direction: column; gap: 4px; }
  .form-group label { font-size: 0.82rem; font-weight: 600; color: #555; }
  .form-group input, .form-group select { padding: 8px 10px; border: 1px solid #ccc; border-radius: 5px; font-size: 0.95rem; }
  .form-group input:focus, .form-group select:focus { outline: none; border-color: #4a90d9; box-shadow: 0 0 0 2px rgba(74,144,217,0.15); }
  #amount { width: 120px; }
  #category { width: 150px; }
  #date { width: 160px; }
  #note { flex: 1; min-width: 150px; }
  #add-expense { padding: 8px 20px; background: #4a90d9; color: #fff; border: none; border-radius: 5px; font-size: 0.95rem; cursor: pointer; font-weight: 600; align-self: flex-end; }
  #add-expense:hover { background: #3a7bc8; }
  #form-error { color: #d32f2f; font-size: 0.88rem; min-height: 1.2em; margin-top: 4px; }

  /* Filters */
  .filters-section { background: #fff; border-radius: 8px; padding: 16px 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.08); }
  .filter-row { display: flex; flex-wrap: wrap; gap: 14px; align-items: flex-end; }
  .filter-row .form-group label { font-size: 0.82rem; font-weight: 600; color: #555; }
  .filter-row input, .filter-row select { padding: 7px 10px; border: 1px solid #ccc; border-radius: 5px; font-size: 0.9rem; }
  .filter-row input:focus, .filter-row select:focus { outline: none; border-color: #4a90d9; }
  #filter-category { width: 150px; }
  #filter-from, #filter-to { width: 150px; }

  /* Summary */
  .summary-section { background: #fff; border-radius: 8px; padding: 16px 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.08); }
  .summary-row { display: flex; flex-wrap: wrap; gap: 16px; align-items: center; margin-bottom: 8px; }
  .summary-row:last-child { margin-bottom: 0; }
  #total { font-size: 1.3rem; font-weight: 700; color: #2e7d32; }
  .cat-total { font-size: 0.92rem; color: #555; }
  .cat-total strong { color: #333; }

  /* Expense list */
  .list-section { background: #fff; border-radius: 8px; padding: 16px 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.08); }
  .expense { display: flex; flex-wrap: wrap; align-items: center; justify-content: space-between; padding: 10px 12px; border-bottom: 1px solid #eee; gap: 8px; }
  .expense:last-child { border-bottom: none; }
  .expense-amount { font-weight: 700; font-size: 1rem; color: #c62828; min-width: 80px; }
  .expense-cat { background: #e3f2fd; color: #1565c0; padding: 2px 10px; border-radius: 12px; font-size: 0.82rem; font-weight: 600; }
  .expense-date { font-size: 0.88rem; color: #777; }
  .expense-note { font-size: 0.85rem; color: #999; font-style: italic; }
  .exp-del { background: #ef5350; color: #fff; border: none; border-radius: 4px; padding: 4px 12px; font-size: 0.82rem; cursor: pointer; font-weight: 600; }
  .exp-del:hover { background: #d32f2f; }
  .no-expenses { text-align: center; color: #999; padding: 20px; font-style: italic; }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<div class="form-section">
  <h2>Add Expense</h2>
  <div class="form-row">
    <div class="form-group">
      <label for="amount">Amount</label>
      <input type="number" id="amount" min="0" step="0.01" placeholder="0.00">
    </div>
    <div class="form-group">
      <label for="category">Category</label>
      <select id="category">
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="form-group">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="e.g. Weekly shopping">
    </div>
    <button id="add-expense">Add</button>
  </div>
  <div id="form-error"></div>
</div>

<!-- Filters -->
<div class="filters-section">
  <h2>Filters</h2>
  <div class="filter-row">
    <div class="form-group">
      <label for="filter-category">Category</label>
      <select id="filter-category">
        <option value="all">all</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group">
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div class="form-group">
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>
</div>

<!-- Summary -->
<div class="summary-section">
  <h2>Summary</h2>
  <div class="summary-row">
    <span>Total: <span id="total">0.00</span></span>
  </div>
  <div class="summary-row" id="cat-totals"></div>
</div>

<!-- Expense List -->
<div class="list-section">
  <h2>Expenses</h2>
  <div id="expense-list"></div>
</div>

<script>
(function() {
  // --- State ---
  var expenses = [];
  var STORAGE_KEY = 'expense_tracker_data';

  // --- DOM refs ---
  var amountInput = document.getElementById('amount');
  var categorySelect = document.getElementById('category');
  var dateInput = document.getElementById('date');
  var noteInput = document.getElementById('note');
  var addBtn = document.getElementById('add-expense');
  var formError = document.getElementById('form-error');

  var filterCategory = document.getElementById('filter-category');
  var filterFrom = document.getElementById('filter-from');
  var filterTo = document.getElementById('filter-to');

  var totalEl = document.getElementById('total');
  var catTotalsEl = document.getElementById('cat-totals');
  var expenseListEl = document.getElementById('expense-list');

  var categories = ['groceries', 'transport', 'bills', 'fun'];

  // --- Init ---
  function init() {
    var stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      try { expenses = JSON.parse(stored); } catch(e) { expenses = []; }
    }
    // Set default date to today
    dateInput.value = formatDate(new Date());
    render();
  }

  function formatDate(d) {
    var y = d.getFullYear();
    var m = String(d.getMonth() + 1).padStart(2, '0');
    var day = String(d.getDate()).padStart(2, '0');
    return y + '-' + m + '-' + day;
  }

  function save() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // --- Validation ---
  function validate() {
    var val = amountInput.value.trim();
    var dateVal = dateInput.value.trim();

    if (!val || isNaN(Number(val)) || Number(val) <= 0) {
      formError.textContent = 'Please enter a valid positive amount.';
      return false;
    }
    if (!dateVal) {
      formError.textContent = 'Please select a date.';
      return false;
    }
    formError.textContent = '';
    return true;
  }

  // --- Add expense ---
  addBtn.addEventListener('click', function() {
    if (!validate()) return;

    var expense = {
      id: Date.now() + Math.random(),
      amount: parseFloat(amountInput.value),
      category: categorySelect.value,
      date: dateInput.value,
      note: noteInput.value.trim()
    };

    expenses.push(expense);
    save();

    // Reset amount field and clear error
    amountInput.value = '';
    formError.textContent = '';

    render();
  });

  // --- Delete expense ---
  expenseListEl.addEventListener('click', function(e) {
    if (e.target.classList.contains('exp-del')) {
      var id = parseFloat(e.target.getAttribute('data-id'));
      expenses = expenses.filter(function(exp) { return exp.id !== id; });
      save();
      render();
    }
  });

  // --- Filters ---
  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  // --- Filtering ---
  function getFiltered() {
    var catFilter = filterCategory.value;
    var fromVal = filterFrom.value;
    var toVal = filterTo.value;

    return expenses.filter(function(exp) {
      if (catFilter !== 'all' && exp.category !== catFilter) return false;
      if (fromVal && exp.date < fromVal) return false;
      if (toVal && exp.date > toVal) return false;
      return true;
    });
  }

  // --- Render ---
  function render() {
    var filtered = getFiltered();

    // Sort newest first
    filtered.sort(function(a, b) {
      if (b.date !== a.date) return b.date.localeCompare(a.date);
      return b.id - a.id;
    });

    // Total
    var total = filtered.reduce(function(sum, exp) { return sum + exp.amount; }, 0);
    totalEl.textContent = total.toFixed(2);

    // Per-category totals
    var catTotals = {};
    categories.forEach(function(c) { catTotals[c] = 0; });
    filtered.forEach(function(exp) {
      catTotals[exp.category] = (catTotals[exp.category] || 0) + exp.amount;
    });

    catTotalsEl.innerHTML = '';
    categories.forEach(function(c) {
      var div = document.createElement('div');
      div.className = 'cat-total';
      div.setAttribute('data-cat', c);
      div.innerHTML = '<strong>' + c + ':</strong> ' + catTotals[c].toFixed(2);
      catTotalsEl.appendChild(div);
    });

    // Expense list
    expenseListEl.innerHTML = '';
    if (filtered.length === 0) {
      expenseListEl.innerHTML = '<div class="no-expenses">No expenses to display.</div>';
      return;
    }

    filtered.forEach(function(exp) {
      var row = document.createElement('div');
      row.className = 'expense';

      var amountSpan = document.createElement('span');
      amountSpan.className = 'expense-amount';
      amountSpan.textContent = exp.amount.toFixed(2);

      var catSpan = document.createElement('span');
      catSpan.className = 'expense-cat';
      catSpan.textContent = exp.category;

      var dateSpan = document.createElement('span');
      dateSpan.className = 'expense-date';
      dateSpan.textContent = exp.date;

      var noteSpan = document.createElement('span');
      noteSpan.className = 'expense-note';
      noteSpan.textContent = exp.note ? exp.note : '';

      var delBtn = document.createElement('button');
      delBtn.className = 'exp-del';
      delBtn.setAttribute('data-id', exp.id);
      delBtn.textContent = 'Delete';

      row.appendChild(amountSpan);
      row.appendChild(catSpan);
      row.appendChild(dateSpan);
      row.appendChild(noteSpan);
      row.appendChild(delBtn);
      expenseListEl.appendChild(row);
    });
  }

  // --- Start ---
  init();
})();
</script>

</body>
</html>
